import { useEffect, useState } from 'react';
import api from '../api/axios';
import { useAuth } from '../context/AuthContext';

const ROLES = ['Employee', 'Manager', 'Finance', 'Director'];
const STATUS_COLOR = {
  Pending: { bg: '#fef3c7', color: '#92400e' },
  Approved: { bg: '#d1fae5', color: '#065f46' },
  Rejected: { bg: '#fee2e2', color: '#991b1b' },
};

const emptyUser = { name: '', email: '', password: '', role: 'Employee', managerId: '' };
const emptyRule = {
  name: '', description: '', appliesTo: '',
  approvers: [], // [{ approverId, required, order }]
  sequential: false,
  minApprovalPercentage: 100,
};

export default function AdminDashboard() {
  const { user, logout } = useAuth();
  const [tab, setTab] = useState('users');
  const [users, setUsers] = useState([]);
  const [expenses, setExpenses] = useState([]);
  const [rules, setRules] = useState([]);
  const [newUser, setNewUser] = useState(emptyUser);
  const [newRule, setNewRule] = useState(emptyRule);
  const [userError, setUserError] = useState('');
  const [userSuccess, setUserSuccess] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [editingUser, setEditingUser] = useState(null); // { id, name, role, managerId }
  const [editError, setEditError] = useState('');

  useEffect(() => {
    api.get('/users').then((r) => setUsers(r.data));
    api.get('/expenses').then((r) => setExpenses(r.data));
    api.get('/rules').then((r) => setRules(r.data));
  }, []);

  const createUser = async (e) => {
    e.preventDefault();
    setUserError(''); setUserSuccess('');
    try {
      const res = await api.post('/users', newUser);
      setUsers((prev) => [...prev, res.data]);
      setUserSuccess(`✓ ${newUser.role} "${newUser.name}" created. They can now login with ${newUser.email}`);
      setNewUser(emptyUser);
    } catch (err) {
      setUserError(err.response?.data?.message || 'Failed to create user');
    }
  };

  const deleteUser = async (id) => {
    if (!window.confirm('Delete this user?')) return;
    await api.delete(`/users/${id}`);
    setUsers(users.filter((u) => u._id !== id));
  };

  const startEdit = (u) => {
    setEditingUser({ id: u._id, name: u.name, role: u.role, managerId: u.manager?._id || '' });
    setEditError('');
  };

  const saveEdit = async () => {
    setEditError('');
    try {
      const res = await api.put(`/users/${editingUser.id}`, {
        name: editingUser.name,
        role: editingUser.role,
        managerId: editingUser.managerId || null,
      });
      setUsers(users.map((u) => (u._id === editingUser.id ? res.data : u)));
      setEditingUser(null);
    } catch (err) {
      setEditError(err.response?.data?.message || 'Update failed');
    }
  };

  const deleteRule = async (id) => {
    await api.delete(`/rules/${id}`);
    setRules(rules.filter((r) => r._id !== id));
  };

  const overrideExpense = async (id, status) => {
    await api.put(`/expenses/${id}/override`, { status });
    const res = await api.get('/expenses');
    setExpenses(res.data);
  };

  const managers = users.filter((u) => u.role === 'Manager');
  const setU = (k) => (e) => setNewUser({ ...newUser, [k]: e.target.value });

  return (
    <div style={s.page}>
      <div style={s.header}>
        <div>
          <h2 style={{ margin: 0 }}>Admin Dashboard</h2>
          <span style={s.sub}>Company: {user?.company?.name}</span>
        </div>
        <button style={s.btnLogout} onClick={logout}>Logout</button>
      </div>

      {/* Tabs */}
      <div style={s.tabs}>
        {['users', 'expenses', 'rules'].map((t) => (
          <button key={t} style={{ ...s.tab, ...(tab === t ? s.activeTab : {}) }} onClick={() => setTab(t)}>
            {t === 'users' ? '👥 Users' : t === 'expenses' ? '💸 Expenses' : '⚙️ Rules'}
          </button>
        ))}
      </div>

      {/* ── USERS TAB ── */}
      {tab === 'users' && (
        <div>
          {/* Create User Form */}
          <div style={s.formCard}>
            <h3 style={s.formTitle}>Create Employee / Manager</h3>
            <p style={s.formHint}>Set the login credentials — they will use this email & password to sign in.</p>

            {userError && <div style={s.alertError}>{userError}</div>}
            {userSuccess && <div style={s.alertSuccess}>{userSuccess}</div>}

            <form onSubmit={createUser}>
              <div style={s.formGrid}>
                <div style={s.field}>
                  <label style={s.label}>Full Name *</label>
                  <input style={s.input} placeholder="e.g. John Smith" required
                    value={newUser.name} onChange={setU('name')} />
                </div>
                <div style={s.field}>
                  <label style={s.label}>Email Address *</label>
                  <input style={s.input} type="email" placeholder="john@company.com" required
                    value={newUser.email} onChange={setU('email')} />
                </div>
                <div style={s.field}>
                  <label style={s.label}>Password *</label>
                  <div style={{ position: 'relative' }}>
                    <input style={{ ...s.input, paddingRight: '2.5rem' }}
                      type={showPassword ? 'text' : 'password'}
                      placeholder="Set login password" required
                      value={newUser.password} onChange={setU('password')} />
                    <button type="button" onClick={() => setShowPassword(!showPassword)}
                      style={s.eyeBtn}>{showPassword ? '🙈' : '👁️'}</button>
                  </div>
                </div>
                <div style={s.field}>
                  <label style={s.label}>Role *</label>
                  <select style={s.input} value={newUser.role} onChange={setU('role')}>
                    {ROLES.map((r) => <option key={r}>{r}</option>)}
                  </select>
                </div>
                {newUser.role === 'Employee' && (
                  <div style={s.field}>
                    <label style={s.label}>Assign Manager</label>
                    <select style={s.input} value={newUser.managerId} onChange={setU('managerId')}>
                      <option value="">— No Manager —</option>
                      {managers.map((m) => <option key={m._id} value={m._id}>{m.name}</option>)}
                    </select>
                  </div>
                )}
              </div>
              <button style={s.btnCreate} type="submit">Create Account</button>
            </form>
          </div>

          {/* Users Table */}
          <div style={s.tableWrap}>
            {editError && <div style={{ ...s.alertError, margin: '0.5rem 1rem' }}>{editError}</div>}
            <table style={s.table}>
              <thead>
                <tr style={s.thead}>
                  {['Name', 'Email', 'Role', 'Manager', 'Action'].map((h) => (
                    <th key={h} style={s.th}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {users.map((u) => (
                  editingUser?.id === u._id ? (
                    // ── Inline Edit Row ──
                    <tr key={u._id} style={{ ...s.tr, background: '#fefce8' }}>
                      <td style={s.td}>
                        <input style={s.cellInput} value={editingUser.name}
                          onChange={(e) => setEditingUser({ ...editingUser, name: e.target.value })} />
                      </td>
                      <td style={s.td}>{u.email}</td>
                      <td style={s.td}>
                        <select style={s.cellInput} value={editingUser.role}
                          onChange={(e) => setEditingUser({ ...editingUser, role: e.target.value })}>
                          {ROLES.map((r) => <option key={r}>{r}</option>)}
                        </select>
                      </td>
                      <td style={s.td}>
                        <select style={s.cellInput} value={editingUser.managerId}
                          onChange={(e) => setEditingUser({ ...editingUser, managerId: e.target.value })}>
                          <option value="">— No Manager —</option>
                          {managers.filter((m) => m._id !== u._id).map((m) => (
                            <option key={m._id} value={m._id}>{m.name}</option>
                          ))}
                        </select>
                      </td>
                      <td style={s.td}>
                        <button style={{ ...s.btnSmall, background: '#10b981', color: '#fff', marginRight: '0.3rem' }}
                          onClick={saveEdit}>Save</button>
                        <button style={{ ...s.btnSmall, background: '#f3f4f6', color: '#374151' }}
                          onClick={() => setEditingUser(null)}>Cancel</button>
                      </td>
                    </tr>
                  ) : (
                    // ── Normal Row ──
                    <tr key={u._id} style={s.tr}>
                      <td style={s.td}>{u.name}</td>
                      <td style={s.td}>{u.email}</td>
                      <td style={s.td}>
                        <span style={{ ...s.roleBadge, ...roleColor(u.role) }}>{u.role}</span>
                      </td>
                      <td style={s.td}>{u.manager?.name || '—'}</td>
                      <td style={s.td}>
                        <button style={{ ...s.btnSmall, background: '#dbeafe', color: '#1e40af', marginRight: '0.3rem' }}
                          onClick={() => startEdit(u)}>Edit</button>
                        <button style={s.btnDanger} onClick={() => deleteUser(u._id)}>Delete</button>
                      </td>
                    </tr>
                  )
                ))}
                {users.length === 0 && (
                  <tr><td colSpan={5} style={s.empty}>No users yet</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ── EXPENSES TAB ── */}
      {tab === 'expenses' && (
        <div style={s.tableWrap}>
          <table style={s.table}>
            <thead>
              <tr style={s.thead}>
                {['Employee', 'Category', 'Vendor', 'Amount', 'Date', 'Status', 'Override'].map((h) => (
                  <th key={h} style={s.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {expenses.map((e) => (
                <tr key={e._id} style={s.tr}>
                  <td style={s.td}>{e.employee?.name}</td>
                  <td style={s.td}>{e.category}</td>
                  <td style={s.td}>{e.ocrData?.vendor || '—'}</td>
                  <td style={s.td}>{e.currency} {Number(e.amount).toFixed(2)}</td>
                  <td style={s.td}>{new Date(e.date).toLocaleDateString()}</td>
                  <td style={s.td}>
                    <span style={{ ...s.badge, ...STATUS_COLOR[e.status] }}>{e.status}</span>
                  </td>
                  <td style={s.td}>
                    <button style={{ ...s.btnSmall, background: '#10b981', color: '#fff', marginRight: '0.3rem' }}
                      onClick={() => overrideExpense(e._id, 'Approved')}>Approve</button>
                    <button style={{ ...s.btnSmall, background: '#ef4444', color: '#fff' }}
                      onClick={() => overrideExpense(e._id, 'Rejected')}>Reject</button>
                  </td>
                </tr>
              ))}
              {expenses.length === 0 && (
                <tr><td colSpan={7} style={s.empty}>No expenses yet</td></tr>
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* ── RULES TAB ── */}
      {tab === 'rules' && (
        <RulesTab users={users} rules={rules} setRules={setRules} companyId={user?.company?._id} />
      )}
    </div>
  );
}

// ─────────────────────────────────────────────
// Rules Tab Component
// ─────────────────────────────────────────────
function RulesTab({ users, rules, setRules }) {
  const blank = {
    name: '', description: '', appliesTo: '',
    type: 'sequential',
    steps: [], // [{ approverId, order, required }]
    minApprovalPercentage: 60,
    autoApproveIf: '',
  };
  const [form, setForm] = useState(blank);
  const [selectedApprover, setSelectedApprover] = useState('');
  const [error, setError] = useState('');

  const approvers = users.filter((u) => u.role !== 'Employee');

  const addApprover = () => {
    if (!selectedApprover) return;
    if (form.steps.find((s) => s.approverId === selectedApprover)) return;
    const order = form.steps.length + 1;
    setForm({ ...form, steps: [...form.steps, { approverId: selectedApprover, order, required: false }] });
    setSelectedApprover('');
  };

  const removeStep = (id) =>
    setForm({ ...form, steps: form.steps.filter((s) => s.approverId !== id).map((s, i) => ({ ...s, order: i + 1 })) });

  const toggleRequired = (id) =>
    setForm({ ...form, steps: form.steps.map((s) => s.approverId === id ? { ...s, required: !s.required } : s) });

  const handleSubmit = async (e) => {
    e.preventDefault(); setError('');
    if (form.steps.length === 0) return setError('Add at least one approver.');
    try {
      const payload = {
        ...form,
        appliesTo: form.appliesTo || null,
        autoApproveIf: form.type === 'hybrid' ? (form.autoApproveIf || null) : null,
        minApprovalPercentage: form.type === 'sequential' ? 100 : Number(form.minApprovalPercentage),
      };
      const res = await api.post('/rules', payload);
      setRules((prev) => [...prev, res.data]);
      setForm(blank);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed');
    }
  };

  const deleteRule = async (id) => {
    await api.delete(`/rules/${id}`);
    setRules((prev) => prev.filter((r) => r._id !== id));
  };

  const getName = (id) => users.find((u) => u._id === id)?.name || '?';

  const typeInfo = {
    sequential: 'Approvers go one-by-one. Next person only sees it after previous approves.',
    parallel: 'All approvers get it at the same time. Approved when minimum % is reached.',
    hybrid: 'All approvers get it at once. Auto-approved if special approver approves, otherwise waits for %.',
  };

  return (
    <div>
      <div style={s.formCard}>
        <h3 style={s.formTitle}>Create Approval Rule</h3>
        {error && <div style={s.alertError}>{error}</div>}

        <form onSubmit={handleSubmit}>
          {/* Basic Info */}
          <div style={s.formGrid}>
            <div style={s.field}>
              <label style={s.label}>Rule Name *</label>
              <input style={s.input} placeholder="e.g. Default Expense Rule" required
                value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} />
            </div>
            <div style={s.field}>
              <label style={s.label}>Applies To</label>
              <select style={s.input} value={form.appliesTo}
                onChange={(e) => setForm({ ...form, appliesTo: e.target.value })}>
                <option value="">— All Employees —</option>
                {users.filter((u) => u.role === 'Employee').map((u) => (
                  <option key={u._id} value={u._id}>{u.name}</option>
                ))}
              </select>
            </div>
            <div style={s.field}>
              <label style={s.label}>Description</label>
              <input style={s.input} placeholder="Optional note"
                value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} />
            </div>
          </div>

          {/* Rule Type */}
          <div style={{ marginBottom: '1rem' }}>
            <label style={s.label}>Rule Type *</label>
            <div style={{ display: 'flex', gap: '0.75rem', marginTop: '0.4rem', flexWrap: 'wrap' }}>
              {['sequential', 'parallel', 'hybrid'].map((t) => (
                <label key={t} style={{
                  display: 'flex', alignItems: 'center', gap: '0.4rem', cursor: 'pointer',
                  padding: '0.5rem 1rem', borderRadius: '6px', border: '2px solid',
                  borderColor: form.type === t ? '#4f46e5' : '#e5e7eb',
                  background: form.type === t ? '#ede9fe' : '#fff',
                  fontWeight: form.type === t ? 700 : 400,
                }}>
                  <input type="radio" name="type" value={t} checked={form.type === t}
                    onChange={() => setForm({ ...form, type: t })} style={{ display: 'none' }} />
                  {t === 'sequential' ? '🔢 Sequential' : t === 'parallel' ? '⚡ Parallel' : '🔀 Hybrid'}
                </label>
              ))}
            </div>
            <p style={{ margin: '0.4rem 0 0', color: '#6b7280', fontSize: '0.82rem' }}>{typeInfo[form.type]}</p>
          </div>

          {/* Approvers */}
          <div style={{ marginBottom: '1rem' }}>
            <label style={s.label}>Approvers (in order)</label>
            <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.75rem', marginTop: '0.4rem' }}>
              <select style={{ ...s.input, flex: 1 }} value={selectedApprover}
                onChange={(e) => setSelectedApprover(e.target.value)}>
                <option value="">Select approver</option>
                {approvers.map((u) => (
                  <option key={u._id} value={u._id}>{u.name} ({u.role})</option>
                ))}
              </select>
              <button type="button" style={s.btnCreate} onClick={addApprover}>+ Add</button>
            </div>

            {form.steps.length > 0 && (
              <div style={s.tableWrap}>
                <table style={s.table}>
                  <thead>
                    <tr style={s.thead}>
                      <th style={s.th}>Step</th>
                      <th style={s.th}>Approver</th>
                      <th style={s.th}>Role</th>
                      {form.type === 'hybrid' && <th style={{ ...s.th, textAlign: 'center' }}>Auto-approve trigger</th>}
                      <th style={s.th}></th>
                    </tr>
                  </thead>
                  <tbody>
                    {form.steps.map((step) => {
                      const u = users.find((u) => u._id === step.approverId);
                      return (
                        <tr key={step.approverId} style={s.tr}>
                          <td style={s.td}>{step.order}</td>
                          <td style={s.td}><strong>{u?.name}</strong></td>
                          <td style={s.td}>
                            <span style={{ ...s.roleBadge, ...roleColor(u?.role) }}>{u?.role}</span>
                          </td>
                          {form.type === 'hybrid' && (
                            <td style={{ ...s.td, textAlign: 'center' }}>
                              <input type="radio" name="autoApproveIf"
                                checked={form.autoApproveIf === step.approverId}
                                onChange={() => setForm({ ...form, autoApproveIf: step.approverId })} />
                            </td>
                          )}
                          <td style={s.td}>
                            <button type="button" style={s.btnDanger} onClick={() => removeStep(step.approverId)}>
                              Remove
                            </button>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>

          {/* Min % — only for parallel/hybrid */}
          {(form.type === 'parallel' || form.type === 'hybrid') && (
            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem', flexWrap: 'wrap' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <label style={s.label}>Min Approval %</label>
                <input style={{ ...s.input, width: '80px' }} type="number" min="1" max="100"
                  value={form.minApprovalPercentage}
                  onChange={(e) => setForm({ ...form, minApprovalPercentage: e.target.value })} />
              </div>
              {form.steps.length > 0 && (
                <span style={{ color: '#6b7280', fontSize: '0.85rem' }}>
                  = at least {Math.ceil(form.steps.length * form.minApprovalPercentage / 100)} of {form.steps.length} approvals needed
                </span>
              )}
            </div>
          )}

          <button style={s.btnCreate} type="submit">Save Rule</button>
        </form>
      </div>

      {/* Existing Rules List */}
      <h3 style={{ ...s.formTitle, marginBottom: '0.75rem' }}>Active Rules</h3>
      {rules.length === 0 && <p style={{ color: '#9ca3af' }}>No rules yet. Create one above.</p>}
      {rules.map((r) => (
        <div key={r._id} style={s.ruleCard}>
          <div style={{ flex: 1 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.3rem', flexWrap: 'wrap' }}>
              <strong>{r.name}</strong>
              <span style={{
                ...s.ruleType,
                background: r.type === 'sequential' ? '#dbeafe' : r.type === 'parallel' ? '#d1fae5' : '#fef3c7',
                color: r.type === 'sequential' ? '#1e40af' : r.type === 'parallel' ? '#065f46' : '#92400e',
              }}>
                {r.type === 'sequential' ? '🔢 Sequential' : r.type === 'parallel' ? '⚡ Parallel' : '🔀 Hybrid'}
              </span>
              {r.appliesTo && (
                <span style={{ ...s.ruleType, background: '#ede9fe', color: '#5b21b6' }}>
                  For: {r.appliesTo.name}
                </span>
              )}
            </div>
            {r.description && <p style={{ margin: '0 0 0.4rem', color: '#6b7280', fontSize: '0.82rem' }}>{r.description}</p>}
            <div style={{ display: 'flex', gap: '0.4rem', flexWrap: 'wrap', marginBottom: '0.3rem' }}>
              {r.steps.sort((a, b) => a.order - b.order).map((step, i) => (
                <span key={i} style={{ background: '#f3f4f6', padding: '0.15rem 0.6rem', borderRadius: '999px', fontSize: '0.78rem', fontWeight: 600 }}>
                  {step.order}. {step.approverId?.name}
                  {r.autoApproveIf?._id === step.approverId?._id && ' ⚡'}
                </span>
              ))}
            </div>
            {r.type !== 'sequential' && (
              <span style={{ fontSize: '0.8rem', color: '#6b7280' }}>
                Min {r.minApprovalPercentage}% approval required
              </span>
            )}
            {r.autoApproveIf && (
              <span style={{ fontSize: '0.8rem', color: '#92400e', marginLeft: '0.75rem' }}>
                ⚡ Auto-approve if {r.autoApproveIf.name} approves
              </span>
            )}
          </div>
          <button style={s.btnDanger} onClick={() => deleteRule(r._id)}>Delete</button>
        </div>
      ))}
    </div>
  );
}

const roleColor = (role) => {
  const map = {
    Admin: { bg: '#ede9fe', color: '#5b21b6' },
    Manager: { bg: '#dbeafe', color: '#1e40af' },
    Finance: { bg: '#fef3c7', color: '#92400e' },
    Director: { bg: '#fce7f3', color: '#9d174d' },
    Employee: { bg: '#f0fdf4', color: '#166534' },
  };
  return map[role] || { bg: '#f3f4f6', color: '#374151' };
};

